/* Hallmark · genre: modern-minimal · design-system: design.md · designed-as-app
 * Carnival / Cold Snap structure · brand orange remaps mustard
 * pre-emit critique: P5 H5 E5 S5 R5 V4 · tokens: pass (48)
 */

:root {
  color-scheme: light;

  /* Hallmark Cold Snap roles (brand orange = mustard role) */
  --color-paper: oklch(92% 0.045 50);
  --color-paper-2: oklch(88% 0.05 45);
  --color-paper-3: oklch(82% 0.06 40);
  --color-ink: oklch(18% 0.08 20);
  --color-ink-2: oklch(28% 0.06 25);
  --color-muted: oklch(45% 0.05 30);
  --color-rule: oklch(40% 0.18 25);
  --color-accent: #ff6b35;
  --color-accent-hover: #ff7f52;
  --color-accent-soft: rgba(255, 107, 53, 0.14);
  --color-accent-2: oklch(40% 0.21 25);
  --color-accent-ink: oklch(18% 0.08 20);
  --color-focus: oklch(40% 0.21 25);

  /* Base (panel / marketing shared names) */
  --bg-base: var(--color-paper);
  --bg-surface: var(--color-paper);
  --bg-surface-hover: var(--color-paper-2);

  /* Borders → Cold Snap rules */
  --border-subtle: color-mix(in srgb, var(--color-rule) 55%, var(--color-paper-2));
  --border-hover: var(--color-rule);

  /* Accents — orange primary; quiet secondary roles (no Night Flight neon) */
  --accent-primary: var(--color-accent);
  --accent-primary-hover: var(--color-accent-hover);
  --accent-blue: var(--color-ink-2);
  --accent-purple: var(--color-rule);
  --accent-green: oklch(42% 0.09 145);

  --accent-primary-soft: var(--color-accent-soft);
  --accent-blue-soft: color-mix(in srgb, var(--color-ink-2) 12%, var(--color-paper));
  --accent-purple-soft: color-mix(in srgb, var(--color-rule) 12%, var(--color-paper));
  --accent-green-soft: color-mix(in srgb, var(--accent-green) 14%, var(--color-paper));

  /* Text */
  --text-primary: var(--color-ink);
  --text-secondary: var(--color-ink-2);
  --text-muted: var(--color-muted);
  --text-on-accent: var(--color-accent-ink);

  /* Atmosphere — no multi-hue glow carnival */
  --glow-blue: radial-gradient(circle, transparent 0%, transparent 70%);
  --glow-purple: radial-gradient(circle, transparent 0%, transparent 70%);
  --glow-orange: radial-gradient(circle, color-mix(in srgb, var(--color-accent) 35%, transparent) 0%, transparent 70%);

  /* Elevation — hard-offset Carnival shadows */
  --shadow-card: 4px 4px 0 var(--color-ink);
  --shadow-sm: 2px 2px 0 var(--color-ink);
  --radius-card: 0.25rem;
  --radius-button: 0.25rem;
  --radius-pill: 0.25rem;
  --radius-input: 0.25rem;

  /* Typography stacks (faces loaded by page) */
  --font-display: "Big Shoulders Display", "Manrope", system-ui, sans-serif;
  --font-body: "Manrope", system-ui, sans-serif;
  --font-mono: "JetBrains Mono", ui-monospace, monospace;

  /* Panel aliases — keep existing class names working */
  --bg: var(--bg-base);
  --bg-elevated: var(--bg-surface);
  --surface: var(--bg-surface);
  --surface2: var(--bg-surface-hover);
  --surface-hover: var(--bg-surface-hover);
  --border: var(--border-subtle);
  --border-strong: var(--color-rule);
  --text: var(--text-primary);
  --muted: var(--text-muted);
  --accent: var(--accent-primary);
  --accent-hover: var(--accent-primary-hover);
  --accent-soft: var(--accent-primary-soft);
  --success: var(--accent-green);
  --success-soft: var(--accent-green-soft);
  --warn: oklch(55% 0.14 55);
  --warn-soft: color-mix(in srgb, var(--warn) 14%, var(--color-paper));
  --danger: var(--color-rule);
  --danger-soft: color-mix(in srgb, var(--color-rule) 12%, var(--color-paper));
  --referral: var(--color-ink-2);
  --referral-soft: var(--accent-blue-soft);
  --visa: var(--color-rule);
  --visa-soft: var(--accent-purple-soft);
  --brand-sky: var(--color-ink-2);
  --brand-sky-soft: var(--accent-blue-soft);
  --brand-gradient: linear-gradient(
    135deg,
    var(--accent-primary) 0%,
    var(--accent-primary-hover) 100%
  );
  --brand-gradient-soft: linear-gradient(
    135deg,
    var(--accent-primary-soft) 0%,
    color-mix(in srgb, var(--color-accent) 8%, var(--color-paper)) 100%
  );
  --radius: var(--radius-card);
  --radius-sm: var(--radius-button);
  --shadow: var(--shadow-card);

  /* Structure helpers */
  --rule-width: 2px;
  --shadow-offset: 4px;
  --shadow-offset-sm: 2px;
}

