import type { Metadata } from "next";
import { Big_Shoulders_Display, JetBrains_Mono, Manrope } from "next/font/google";
import "./globals.css";

const manrope = Manrope({
  subsets: ["latin"],
  weight: ["400", "500", "600", "700", "800"],
  variable: "--font-body",
  display: "swap",
});

const bigShoulders = Big_Shoulders_Display({
  subsets: ["latin"],
  weight: ["700", "800"],
  variable: "--font-display",
  display: "swap",
});

const jetbrains = JetBrains_Mono({
  subsets: ["latin"],
  weight: ["400", "500"],
  variable: "--font-mono",
  display: "swap",
});

export const metadata: Metadata = {
  metadataBase: new URL("https://kuchup.com"),
  title: {
    template: "%s | Relocation Jobs",
    default: "Relocation Jobs | Visa-Sponsored Software Roles in Europe",
  },
  description:
    "Find visa-sponsored software engineering roles in Europe. Search relocation-friendly openings in Germany, Netherlands, UK, Portugal, and Ireland. Track applications and tailor your CV.",
  icons: {
    icon: [{ url: "/static/icons/kuchup-bird.svg", type: "image/svg+xml" }],
    apple: [{ url: "/static/icons/apple-touch-icon.png" }],
  },
  openGraph: {
    title: "Relocation Jobs",
    description:
      "Find visa-sponsored engineering roles in Europe — before they're gone.",
    url: "https://kuchup.com/",
    siteName: "Relocation Jobs",
    type: "website",
    locale: "en_GB",
  },
  twitter: {
    card: "summary",
    title: "Relocation Jobs",
    description:
      "Find visa-sponsored engineering roles in Europe — before they're gone.",
  },
  robots: {
    index: true,
    follow: true,
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const jsonLd = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Relocation Jobs",
        alternateName: "KUCHUP",
        url: "https://kuchup.com/",
        description:
          "Curated visa-sponsored software engineering roles across Europe.",
        sameAs: ["https://github.com/AminMortezaie/relocation-jobs"],
      },
      {
        "@type": "WebSite",
        name: "Relocation Jobs",
        url: "https://kuchup.com/",
        description:
          "Find visa-sponsored software engineering roles in Germany, Netherlands, UK, Portugal, and Ireland.",
      },
    ],
  };

  return (
    <html
      lang="en"
      className={`${manrope.variable} ${bigShoulders.variable} ${jetbrains.variable}`}
    >
      <body className={manrope.className}>
        <script
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
        />
        {children}
      </body>
    </html>
  );
}

/* Hallmark · genre: modern-minimal · macrostructure: feature-stack · design-system: design.md · designed-as-app */
@import "./design-tokens.css";
@import "tailwindcss/base";
@import "tailwindcss/components";
@import "tailwindcss/utilities";

html {
  scroll-behavior: smooth;
  overflow-x: clip;
}

body {
  @apply font-sans font-normal text-text-primary antialiased;
  font-family: var(--font-body), system-ui, sans-serif;
  background: var(--bg-base);
  color: var(--text-primary);
  overflow-x: clip;
}

/* ── Typography ── */

.text-fluid-hero {
  font-family: var(--font-display), var(--font-body), system-ui, sans-serif;
  font-size: clamp(2.25rem, 4vw + 1rem, 3.5rem);
  font-style: normal;
  font-weight: 800;
  letter-spacing: -0.005em;
  line-height: 0.95;
  text-transform: uppercase;
}

.text-section-title {
  font-family: var(--font-display), var(--font-body), system-ui, sans-serif;
  font-size: clamp(1.5rem, 1.5vw + 1rem, 2rem);
  font-style: normal;
  font-weight: 800;
  letter-spacing: 0.015em;
  line-height: 1.1;
  text-transform: uppercase;
}

.font-display {
  font-family: var(--font-display), var(--font-body), system-ui, sans-serif;
  font-style: normal;
}

/* ── Cold Snap cards ── */

.card {
  background: var(--bg-surface);
  border: var(--rule-width) solid var(--color-rule);
  box-shadow: var(--shadow-card);
  border-radius: var(--radius-card);
}

.card-interactive {
  transition:
    transform var(--dur-short, 180ms) var(--ease-out, cubic-bezier(0.16, 1, 0.3, 1)),
    border-color var(--dur-short, 180ms) var(--ease-out, cubic-bezier(0.16, 1, 0.3, 1)),
    box-shadow var(--dur-short, 180ms) var(--ease-out, cubic-bezier(0.16, 1, 0.3, 1));
}

.card-interactive:hover {
  border-color: var(--color-ink);
  transform: translateY(1px);
  box-shadow: 2px 2px 0 var(--color-ink);
}

.surface-card {
  background: var(--bg-surface);
  border: var(--rule-width) solid var(--color-rule);
  box-shadow: var(--shadow-card);
  border-radius: var(--radius-card);
}

.surface-card-interactive {
  transition:
    transform var(--dur-short, 180ms) var(--ease-out, cubic-bezier(0.16, 1, 0.3, 1)),
    border-color var(--dur-short, 180ms) var(--ease-out, cubic-bezier(0.16, 1, 0.3, 1)),
    box-shadow var(--dur-short, 180ms) var(--ease-out, cubic-bezier(0.16, 1, 0.3, 1));
}

.surface-card-interactive:hover {
  border-color: var(--color-ink);
  transform: translateY(1px);
  box-shadow: 2px 2px 0 var(--color-ink);
}

/* ── Buttons ── */

.btn-primary {
  background: var(--accent-primary);
  color: var(--text-on-accent);
  border: var(--rule-width) solid var(--color-ink);
  border-radius: var(--radius-button);
  box-shadow: var(--shadow-sm);
  min-height: 2.75rem;
  transition:
    background 160ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 100ms cubic-bezier(0.16, 1, 0.3, 1),
    box-shadow 160ms cubic-bezier(0.16, 1, 0.3, 1);
}

.btn-primary:hover {
  background: var(--accent-primary-hover);
}

.btn-primary:active {
  transform: translateY(1px);
  box-shadow: none;
}

.btn-secondary {
  background: var(--color-paper);
  color: var(--text-primary);
  border: var(--rule-width) solid var(--color-rule);
  border-radius: var(--radius-button);
  min-height: 2.75rem;
  box-shadow: var(--shadow-sm);
  transition:
    border-color 160ms cubic-bezier(0.16, 1, 0.3, 1),
    background 160ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 100ms cubic-bezier(0.16, 1, 0.3, 1);
}

.btn-secondary:hover {
  border-color: var(--color-ink);
  background: var(--color-paper-2);
}

.btn-secondary:active {
  transform: translateY(1px);
  box-shadow: none;
}

/* Legacy glow classes — neutralized (no Night Flight blobs) */

.hero-search-glow {
  position: relative;
}

.hero-search-glow::before {
  content: none;
}

.hero-search-glow > * {
  position: relative;
  z-index: 1;
}

.glow-orange {
  position: relative;
}

.glow-orange::before {
  content: none;
}

.glow-orange > * {
  position: relative;
  z-index: 1;
}

/* ── Form controls ── */

.select-pill {
  @apply w-full appearance-none py-3 pl-10 pr-10 text-sm font-normal;
  border-radius: var(--radius-input);
  color: var(--text-primary);
  border: var(--rule-width) solid var(--border-subtle);
  background: var(--bg-surface-hover);
  min-height: 2.75rem;
  transition:
    border-color 200ms ease,
    box-shadow 200ms ease;
}

.select-pill:focus-visible {
  outline: none;
  border-color: var(--color-focus);
  box-shadow: 0 0 0 3px var(--accent-primary-soft);
}

.select-icon {
  top: calc(50% + 0.5px);
  transform: translateY(-50%);
}

/* ── Focus rings ── */

:focus {
  outline: none;
}

:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 2px;
  box-shadow: none;
}

.btn-primary:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 2px;
}

/* ── Section rhythm ── */

.section-major {
  padding-top: 2.75rem;
  padding-bottom: 2.75rem;
}

@media (min-width: 640px) {
  .section-major {
    padding-top: 3.5rem;
    padding-bottom: 3.5rem;
  }
}

@media (min-width: 1024px) {
  .section-major {
    padding-top: 6rem;
    padding-bottom: 6rem;
  }
}

.section-major-first {
  padding-top: 1.75rem;
  padding-bottom: 2.5rem;
}

@media (min-width: 640px) {
  .section-major-first {
    padding-top: 2.5rem;
    padding-bottom: 3.5rem;
  }
}

@media (min-width: 1024px) {
  .section-major-first {
    padding-top: 3.5rem;
    padding-bottom: 6rem;
  }
}

.section-compact {
  padding-top: 1.5rem;
  padding-bottom: 1.5rem;
}

@media (min-width: 640px) {
  .section-compact {
    padding-top: 2rem;
    padding-bottom: 2rem;
  }
}

.mobile-menu-panel {
  transform-origin: top right;
  border: var(--rule-width) solid var(--color-rule);
  border-radius: var(--radius-card);
  background: var(--color-paper);
  box-shadow: var(--shadow-card);
  transition:
    opacity 180ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 180ms cubic-bezier(0.16, 1, 0.3, 1),
    visibility 0ms linear 180ms;
}

.mobile-menu-panel[data-open="false"] {
  opacity: 0;
  transform: scale(0.97);
  pointer-events: none;
  visibility: hidden;
}

.mobile-menu-panel[data-open="true"] {
  opacity: 1;
  transform: scale(1);
  pointer-events: auto;
  visibility: visible;
  transition:
    opacity 180ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 180ms cubic-bezier(0.16, 1, 0.3, 1),
    visibility 0ms linear 0ms;
}

/* ── Pill controls (nav, filters) ── */

.pill-control {
  @apply inline-flex items-center px-3.5 py-1.5;
  border-radius: var(--radius-button);
  color: var(--text-primary);
  border: var(--rule-width) solid var(--border-subtle);
  background: var(--bg-surface);
  min-height: 2.75rem;
  transition:
    border-color 200ms ease,
    color 200ms ease;
}

.pill-control:hover {
  border-color: var(--color-rule);
  color: var(--text-primary);
}

/* ── Sticky nav ── */

.nav-glass {
  background: var(--color-paper);
  border: var(--rule-width) solid var(--color-rule);
  box-shadow: var(--shadow-card);
}

/* ── Entrance (page load) ── */

@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.hero-enter {
  animation: fade-up 400ms cubic-bezier(0.16, 1, 0.3, 1) both;
}

.hero-enter-delay-1 {
  animation-delay: 80ms;
}

.hero-enter-delay-2 {
  animation-delay: 160ms;
}

.hero-enter-delay-3 {
  animation-delay: 240ms;
}

/* ── Scroll reveal ── */

.reveal-card {
  transition:
    opacity 500ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 500ms cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal-card.reveal-pending:not(.is-visible) {
  opacity: 0;
  transform: translateY(12px);
}

.reveal-card.is-visible {
  opacity: 1;
  transform: translateY(0);
}

.reveal-card.card-interactive.is-visible:hover,
.reveal-card.surface-card-interactive.is-visible:hover {
  transform: translateY(1px);
}

@keyframes pill-swap-in {
  from {
    opacity: 0;
    transform: translateY(3px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.alive-pill-swap {
  animation: pill-swap-in 320ms cubic-bezier(0.16, 1, 0.3, 1);
}

/* ── Reduced motion ── */

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }

  .hero-enter,
  .hero-enter-delay-1,
  .hero-enter-delay-2,
  .hero-enter-delay-3 {
    animation: none;
  }

  .reveal-card.reveal-pending:not(.is-visible) {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .reveal-card {
    transition: none;
  }

  .card-interactive,
  .surface-card-interactive {
    transition: border-color 200ms ease;
  }

  .card-interactive:hover,
  .surface-card-interactive:hover {
    transform: none;
  }

  .btn-primary:hover,
  .btn-primary:active {
    transform: none;
  }

  .btn-secondary:active {
    transform: none;
  }

  .mobile-menu-panel {
    transition: none;
  }

  .alive-pill-swap {
    animation: none;
  }

  .btn-primary {
    transition: background 200ms ease;
  }
}

