      for (const el of els) {
        const r=el.getBoundingClientRect();
        if (r.width<150||r.height<150) continue;
        const s=getComputedStyle(el);
        const bImg=s.backgroundImage;
        const brNum=parseFloat(s.borderTopLeftRadius)||0;
        const round = s.borderTopLeftRadius.includes('%') || brNum>=Math.min(r.width,r.height)/2-4;
        const isSvg = ['svg','circle','ellipse'].includes(el.tagName.toLowerCase());
        const grad = bImg && bImg!=='none';
        if (round||isSvg||grad) {
          out.push({tag:el.tagName, cls:(el.getAttribute('class')||'').slice(0,60), id:el.id, w:Math.round(r.width), h:Math.round(r.height), br:s.borderTopLeftRadius, bImg:bImg.slice(0,80)});
        }
      }
      // also pseudo elements on likely containers
      const pseudo=[];
      for (const sel of ['body','.layout','.admin-layout','.admin-content','.admin-panel','.admin-section','.admin-table-wrap','.admin-table']) {
        for (const el of document.querySelectorAll(sel)) {
          for (const pe of ['::before','::after']) {
            const cs=getComputedStyle(el,pe);
            if (cs.content && cs.content!=='none' && (cs.backgroundImage!=='none' || parseFloat(cs.width)>150)) {
              pseudo.push({sel, pe, w:cs.width, h:cs.height, bImg:cs.backgroundImage.slice(0,80), border:cs.border, br:cs.borderRadius});
            }
          }
        }
      }
      return {out, pseudo, url:location.href};
    }''')
    print('URL', data['url'])
    print('--- big elements ---')
    for x in data['out']: print(x)
    print('--- pseudo ---')
    for x in data['pseudo']: print(x)
    pg.screenshot(path='/tmp/admin_desktop.png', full_page=False)
    b.close()
